import Link from 'next/link'
import { Facebook, Instagram, Twitter, Linkedin, Github } from 'lucide-react'

interface FooterProps {
    ownerName?: string
    facebookUrl?: string
    instagramUrl?: string
    twitterUrl?: string
    linkedinUrl?: string
    githubUrl?: string
}

export function Footer({
    ownerName = 'John Doe',
    facebookUrl = '',
    instagramUrl = '',
    twitterUrl = '',
    linkedinUrl = '',
    githubUrl = ''
}: FooterProps) {
    const socialLinks = [
        { url: facebookUrl, icon: Facebook, label: 'Facebook' },
        { url: instagramUrl, icon: Instagram, label: 'Instagram' },
        { url: twitterUrl, icon: Twitter, label: 'Twitter' },
        { url: linkedinUrl, icon: Linkedin, label: 'LinkedIn' },
        { url: githubUrl, icon: Github, label: 'GitHub' },
    ].filter(link => link.url) // Only show icons that have URLs

    const footerLinks = [
        { href: '/', label: 'Home' },
        { href: '/works', label: 'Works' },
        { href: '/blog', label: 'Blog' },
    ]

    return (
        <footer className="w-full border-t border-border bg-background py-8">
            <div className="container mx-auto flex flex-col items-center gap-6 px-4">
                <nav aria-label="Footer navigation" className="flex flex-wrap items-center justify-center gap-6 text-sm">
                    {footerLinks.map(({ href, label }) => (
                        <Link
                            key={href}
                            href={href}
                            className="text-muted-foreground transition-colors hover:text-brand-accent"
                        >
                            {label}
                        </Link>
                    ))}
                </nav>

                {/* Social Icons */}
                {socialLinks.length > 0 && (
                    <div className="flex items-center gap-6">
                        {socialLinks.map(({ url, icon: Icon, label }) => (
                            <Link
                                key={label}
                                href={url}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-muted-foreground transition-colors hover:text-brand-accent"
                                aria-label={label}
                            >
                                <Icon size={24} />
                            </Link>
                        ))}
                    </div>
                )}

                {/* Copyright */}
                <p className="text-center text-sm text-muted-foreground">
                    &copy; {new Date().getFullYear()} {ownerName}. All rights reserved.
                </p>
            </div>
        </footer>
    )
}
